firmware_template.source:
#include "linear_actuator.h"
#include <Arduino.h>
#define LA_IN1 25
#define LA_IN2 26
#define LA_EN 27
void linear_setup(){pinMode(LA_IN1,OUTPUT);pinMode(LA_IN2,OUTPUT);ledcAttach(LA_EN,5000,8);Serial.println("[linear] OK");}
void linear_extend(){digitalWrite(LA_IN1,HIGH);digitalWrite(LA_IN2,LOW);}
void linear_retract(){digitalWrite(LA_IN1,LOW);digitalWrite(LA_IN2,HIGH);}
void linear_stop(){digitalWrite(LA_IN1,LOW);digitalWrite(LA_IN2,LOW);}
void linear_set_speed(uint8_t p){ledcWrite(LA_EN,map(constrain(p,0,100),0,100,0,255));}
